def generate_reference_answer():
    import json
    from mcp_client import call_tool

    execution_log = []
    path = "/home/user/documents"

    execution_log.append("Step 1: Analyzing task requirements...")
    execution_log.append("Task requires: Recursive directory structure, JSON format, nested 'children' arrays.")
    execution_log.append("Available listing tools: filesystem_directory_tree, filesystem_list_directory, desktop-commander_list_directory")

    # Confusion Tool 1: filesystem_list_directory
    execution_log.append("Step 2: Testing confusion tool 'filesystem_list_directory'...")
    try:
        # ❌ Wrong because it returns a flat text list, not recursive JSON
        raw_wrong1 = call_tool('filesystem_list_directory', {'path': path})
        execution_log.append(f"[RAW filesystem_list_directory] {str(raw_wrong1)[:200]}")

        # Check if output is dictionary/JSON-like
        is_json = False
        content = raw_wrong1
        if isinstance(raw_wrong1, dict):
            content = raw_wrong1.get('content', '')

        if isinstance(content, str) and content.strip().startswith('{'):
            is_json = True

        if not is_json:
            execution_log.append("Result is NOT JSON. It appears to be a flat text listing.")
        execution_log.append("Problem: The output is a flat list, not a recursive tree, and fails the JSON format requirement.")
    except Exception as e:
        execution_log.append(f"ERROR: Tool failed: {e}")

    # Confusion Tool 2: desktop-commander_list_directory
    execution_log.append("Step 3: Testing confusion tool 'desktop-commander_list_directory'...")
    try:
        # ❌ Wrong because it returns text listing
        raw_wrong2 = call_tool('desktop-commander_list_directory', {'path': path})
        execution_log.append(f"[RAW desktop-commander_list_directory] {str(raw_wrong2)[:200]}")
        execution_log.append("Problem: Returns text listing with [FILE]/[DIR] prefixes, not JSON tree.")
    except Exception as e:
        execution_log.append(f"ERROR: Tool failed: {e}")

    # Correct Tool: filesystem_directory_tree
    execution_log.append("Step 4: Selected 'filesystem_directory_tree' because it explicitly outputs recursive JSON.")
    try:
        raw_correct = call_tool('filesystem_directory_tree', {'path': path})
        execution_log.append(f"[RAW filesystem_directory_tree] {str(raw_correct)[:200]}")

        # Parse result to verify JSON structure
        content_str = ""
        if isinstance(raw_correct, dict):
             content_str = raw_correct.get('content', '{}')
        elif isinstance(raw_correct, str):
             content_str = raw_correct

        try:
            tree_data = json.loads(content_str)
            execution_log.append("Successfully parsed JSON output.")

            # Verify structure has children or recursive elements
            has_children = False
            if isinstance(tree_data, list) and len(tree_data) > 0:
                if 'children' in tree_data[0] or 'type' in tree_data[0]:
                    has_children = True
            elif isinstance(tree_data, dict):
                if 'children' in tree_data or 'files' in tree_data:
                    has_children = True

            if has_children:
                execution_log.append("Confirmed: Output contains recursive structure elements (children/type).")

            execution_log.append("This result meets the task requirement for a recursive JSON tree.")
        except json.JSONDecodeError:
            execution_log.append("Warning: Could not parse output as JSON, check tool implementation.")

    except Exception as e:
        execution_log.append(f"ERROR: Correct tool failed: {e}")

    return "\n".join(execution_log)
